def init_db():
    conn = sqlite3.connect('mfa_system.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  email TEXT UNIQUE NOT NULL,
                  password_hash TEXT NOT NULL,
                  mfa_enabled INTEGER DEFAULT 0,
                  mfa_secret TEXT,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
    
    c.execute('''CREATE TABLE IF NOT EXISTS mfa_reset_tokens
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  user_id INTEGER NOT NULL,
                  token TEXT UNIQUE NOT NULL,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  expires_at TIMESTAMP NOT NULL,
                  used INTEGER DEFAULT 0,
                  FOREIGN KEY (user_id) REFERENCES users (id))''')
    
    c.execute('''CREATE TABLE IF NOT EXISTS sessions
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  user_id INTEGER NOT NULL,
                  session_token TEXT UNIQUE NOT NULL,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  FOREIGN KEY (user_id) REFERENCES users (id))''')
    
    conn.commit()
    conn.close()

init_db()

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def get_db():
    conn = sqlite3.connect('mfa_system.db')
    conn.row_factory = sqlite3.Row
    return conn

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_token = request.headers.get('Authorization')
        if not session_token:
            return jsonify({'error': 'Authentication required'}), 401
        
        conn = get_db()
        c = conn.cursor()
        c.execute('SELECT user_id FROM sessions WHERE session_token = ?', (session_token,))
        session = c.fetchone()
        conn.close()
        
        if not session:
            return jsonify({'error': 'Invalid session'}), 401
        
        request.user_id = session['user_id']
        return f(*args, **kwargs)
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    password_hash = hash_password(password)
    
    conn = get_db()
    c = conn.cursor()
    
    try:
        c.execute('INSERT INTO users (email, password_hash) VALUES (?, ?)',
                  (email, password_hash))
        conn.commit()
        user_id = c.lastrowid
        conn.close()
        
        return jsonify({'message': 'User registered successfully', 'user_id': user_id}), 201
    except sqlite3.IntegrityError:
        conn.close()
        return jsonify({'error': 'Email already exists'}), 400

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    mfa_code = data.get('mfa_code')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    password_hash = hash_password(password)
    
    conn = get_db()
    c = conn.cursor()
    c.execute('SELECT * FROM users WHERE email = ? AND password_hash = ?',
              (email, password_hash))
    user = c.fetchone()
    
    if not user:
        conn.close()
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user['mfa_enabled']:
        if not mfa_code:
            conn.close()
            return jsonify({'error': 'MFA code required', 'mfa_required': True}), 401
        
        totp = pyotp.TOTP(user['mfa_secret'])
        if not totp.verify(mfa_code):
            conn.close()
            return jsonify({'error': 'Invalid MFA code'}), 401
    
    session_token = secrets.token_urlsafe(32)
    c.execute('INSERT INTO sessions (user_id, session_token) VALUES (?, ?)',
              (user['id'], session_token))
    conn.commit()
    conn.close()
    
    return jsonify({
        'message': 'Login successful',
        'session_token': session_token,
        'mfa_enabled': bool(user['mfa_enabled'])
    }), 200

@app.route('/mfa/enable', methods=['POST'])
@require_auth
def enable_mfa():
    conn = get_db()
    c = conn.cursor()
    c.execute('SELECT mfa_enabled FROM users WHERE id = ?', (request.user_id,))
    user = c.fetchone()
    
    if user['mfa_enabled']:
        conn.close()
        return jsonify({'error': 'MFA already enabled'}), 400
    
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    
    c.execute('UPDATE users SET mfa_secret = ? WHERE id = ?',
              (secret, request.user_id))
    conn.commit()
    
    c.execute('SELECT email FROM users WHERE id = ?', (request.user_id,))
    user = c.fetchone()
    conn.close()
    
    provisioning_uri = totp.provisioning_uri(user['email'], issuer_name='MFA System')
    
    return jsonify({
        'message': 'MFA secret generated',
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'note': 'Please verify with a code to complete setup'
    }), 200

@app.route('/mfa/verify-enable', methods=['POST'])
@require_auth
def verify_enable_mfa():
    data = request.get_json()
    mfa_code = data.get('mfa_code')
    
    if not mfa_code:
        return jsonify({'error': 'MFA code required'}), 400
    
    conn = get_db()
    c = conn.cursor()
    c.execute('SELECT mfa_secret, mfa_enabled FROM users WHERE id = ?', (request.user_id,))
    user = c.fetchone()
    
    if not user['mfa_secret']:
        conn.close()
        return jsonify({'error': 'MFA not initialized. Call /mfa/enable first'}), 400
    
    if user['mfa_enabled']:
        conn.close()
        return jsonify({'error': 'MFA already enabled'}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(mfa_code):
        conn.close()
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    c.execute('UPDATE users SET mfa_enabled = 1 WHERE id = ?', (request.user_id,))
    conn.commit()
    conn.close()
    
    return jsonify({'message': 'MFA enabled successfully'}), 200

@app.route('/mfa/disable', methods=['POST'])
@require_auth
def disable_mfa():
    data = request.get_json()
    mfa_code = data.get('mfa_code')
    password = data.get('password')
    
    if not mfa_code or not password:
        return jsonify({'error': 'MFA code and password required'}), 400
    
    password_hash = hash_password(password)
    
    conn = get_db()
    c = conn.cursor()
    c.execute('SELECT * FROM users WHERE id = ? AND password_hash = ?',
              (request.user_id, password_hash))
    user = c.fetchone()
    
    if not user:
        conn.close()
        return jsonify({'error': 'Invalid password'}), 401
    
    if not user['mfa_enabled']:
        conn.close()
        return jsonify({'error': 'MFA not enabled'}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(mfa_code):
        conn.close()
