@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email required'}), 400
    
    conn = get_db()
    c = conn.cursor()
    c.execute('SELECT * FROM users WHERE email = ?', (email,))
    user = c.fetchone()
    
    if not user:
        conn.close()
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    if not user['mfa_enabled']:
        conn.close()
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.now() + timedelta(hours=1)
    
    c.execute('INSERT INTO mfa_reset_tokens (user_id, token, expires_at) VALUES (?, ?, ?)',
              (user['id'], token, expires_at))
    conn.commit()
    conn.close()
    
    reset_link = f"{request.host_url}confirm-reset-mfa?token={token}"
    
    try:
        msg = Message('MFA Reset Request',
                      recipients=[email])
        msg.body = f'''
You have requested to reset your MFA settings.

Click the link below to disable MFA and regain access to your account:
{reset_link}

This link will expire in 1 hour.

If you did not request this reset, please ignore this email.
'''
        mail.send(msg)
    except Exception as e:
        print(f"Error sending email: {e}")
    
    return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

@app.route('/confirm-reset-mfa', methods=['GET', 'POST'])
def confirm_reset_mfa():
    token = request.args.get('token') if request.method == 'GET' else request.get_json().get('token')
    
    if not token:
        return jsonify({'error': 'Token required'}), 400
    
    conn = get_db()
    c = conn.cursor()
    c.execute('''SELECT mfa_reset_tokens.*, users.email 
                 FROM mfa_reset_tokens 
                 JOIN users ON mfa_reset_tokens.user_id = users.id
                 WHERE token = ?''', (token,))
    reset_request = c.fetchone()
    
    if not reset_request:
        conn.close()
        return jsonify({'error': 'Invalid or expired token'}), 400
    
    if reset_request['used']:
        conn.close()
        return jsonify({'error': 'Token already used'}), 400
    
    expires_at = datetime.fromisoformat(reset_request['expires_at'])
    if datetime.now() > expires_at:
        conn.close()
        return jsonify({'error': 'Token expired'}), 400
    
    c.execute('UPDATE users SET mfa_enabled = 0, mfa_secret = NULL WHERE id = ?',
              (reset_request['user_id'],))
    c.execute('UPDATE mfa_reset_tokens SET used = 1 WHERE id = ?',
              (reset_request['id'],))
    conn.commit()
    conn.close()
    
    return jsonify({
        'message': 'MFA has been disabled successfully',
        'email': reset_request['email'],
        'note': 'You can now log in with just your password'
    }), 200

